exercises.starterCode:
# Match algorithms to applications
algorithms = {
    "Grover's": {"application": "?", "speedup": "?"},
    "Shor's": {"application": "?", "speedup": "?"},
    "Deutsch-Jozsa": {"application": "?", "speedup": "?"},
    "QFT": {"application": "?", "speedup": "?"}
}

# Fill in the blanks with:
# Applications: search, factoring, function-property, signal-processing
# Speedups: quadratic, exponential

exercises.solution:
algorithms = {
    "Grover's": {"application": "search", "speedup": "quadratic"},
    "Shor's": {"application": "factoring", "speedup": "exponential"},
    "Deutsch-Jozsa": {"application": "function-property", "speedup": "exponential"},
    "QFT": {"application": "signal-processing", "speedup": "exponential"}
}

for name, info in algorithms.items():
    print(f"{name}: {info['application']} ({info['speedup']})")
